import React, { useState, useEffect, useRef } from 'react';
import './VideoPlayer.css';

const VideoPlayer = ({ video }) => {
    const [error, setError] = useState(false);
    const [isLoading, setIsLoading] = useState(true);
    const containerRef = useRef(null);

    useEffect(() => {
        setIsLoading(true);
        setError(false);
    }, [video]);

    const getVideoUrl = (url, type) => {
        if (!url) return '';
        
        const getYouTubeVideoId = (url) => {
            const patterns = [
                /(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([^&\n?#]+)/,
                /youtube\.com\/watch\?.*v=([^&\n?#]+)/
            ];
            
            for (const pattern of patterns) {
                const match = url.match(pattern);
                if (match) return match[1];
            }
            return null;
        };

        if (type === 'youtube') {
            const videoId = getYouTubeVideoId(url);
            if (videoId) {
                // Use youtube-nocookie.com to avoid tracking and embedding restrictions
                return `https://www.youtube-nocookie.com/embed/${videoId}?autoplay=1&mute=0&controls=1&rel=0&modestbranding=1&showinfo=0&iv_load_policy=3&enablejsapi=1&origin=${encodeURIComponent(window.location.origin)}`;
            }
            return url;
        }
        
        if (type === 'vimeo') {
            const vimeoId = url.match(/vimeo\.com\/(\d+)/)?.[1];
            if (vimeoId) {
                return `https://player.vimeo.com/video/${vimeoId}?autoplay=1&title=0&byline=0&portrait=0`;
            }
            return url;
        }
        
        return url;
    };

    const handleLoad = () => {
        setIsLoading(false);
    };

    const handleError = () => {
        setError(true);
        setIsLoading(false);
    };

    if (!video) {
        return (
            <div className="video-placeholder">
                <i className="fas fa-video"></i>
                <p>No promotional video available</p>
                <span>Contact admin to add videos</span>
            </div>
        );
    }

    if (error) {
        return (
            <div className="video-error">
                <i className="fas fa-exclamation-triangle"></i>
                <p>Unable to load video</p>
                <button onClick={() => setError(false)}>Retry</button>
            </div>
        );
    }

    const videoUrl = getVideoUrl(video.video_url, video.video_type);

    return (
        <div className="video-player-container" ref={containerRef}>
            {isLoading && (
                <div className="video-loading">
                    <div className="spinner"></div>
                    <p>Loading video...</p>
                </div>
            )}
            <iframe
                src={videoUrl}
                title={video.title || 'Promotional Video'}
                className="video-iframe"
                frameBorder="0"
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; fullscreen"
                allowFullScreen
                sandbox="allow-same-origin allow-scripts allow-popups allow-forms allow-presentation allow-popups-to-escape-sandbox"
                referrerPolicy="strict-origin-when-cross-origin"
                onLoad={handleLoad}
                onError={handleError}
                style={{
                    opacity: isLoading ? 0 : 1,
                    transition: 'opacity 0.3s ease',
                    position: 'absolute',
                    top: 0,
                    left: 0,
                    width: '100%',
                    height: '100%',
                    border: 'none'
                }}
            />
            {video.title && (
                <div className="video-overlay">
                    <h3>{video.title}</h3>
                    {video.description && <p>{video.description}</p>}
                </div>
            )}
        </div>
    );
};

export default VideoPlayer;
